1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type DamageEntry = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: DamageEntry[] };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	type QuoteResult = { premium: number };
10	type ClaimResult = { payout: number; remainingCap: number };
11	type StepResult = QuoteResult | ClaimResult;
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	const LOYALTY_THRESHOLD_YEARS = 2;
20	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
21	const DEDUCTIBLE = 100;
22	const BASE_PREMIUMS: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	  moonstone: 25,
29	};
30	const INSURANCE_VALUES: Record<string, number> = {
31	  sword: 1000,
32	  amulet: 600,
33	  staff: 800,
34	  potion: 400,
35	  rune: 250,
36	  moonstone: 250,
37	};
38	
39	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
40	const BLOCK_SIZE = 3;
41	const BLOCK_BASE_PREMIUM = 60;
42	
43	const unitBasePremium = (type: string): number => BASE_PREMIUMS[type] ?? 0;
44	
45	const unitInsuranceValue = (type: string): number => INSURANCE_VALUES[type] ?? 0;
46	
47	const isComponentBlock = (type: string, count: number): boolean =>
48	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
49	
50	const groupBasePremium = (type: string, count: number): number =>
51	  isComponentBlock(type, count) ? BLOCK_BASE_PREMIUM : count * unitBasePremium(type);
52	
53	const countByType = (items: Item[]): Map<string, number> =>
54	  items.reduce(
55	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
56	    new Map<string, number>(),
57	  );
58	
59	const itemsBasePremium = (items: Item[]): number =>
60	  [...countByType(items)].reduce(
61	    (total, [type, count]) => total + groupBasePremium(type, count),
62	    0,
63	  );
64	
65	const itemModifierSurcharge = (item: Item): number => {
66	  const base = unitBasePremium(item.type);
67	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
68	  const highEnchantmentSurcharge =
69	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
70	  return curseSurcharge + highEnchantmentSurcharge;
71	};
72	
73	const itemsModifierSurcharge = (items: Item[]): number =>
74	  items.reduce((total, item) => total + itemModifierSurcharge(item), 0);
75	
76	const loyaltyDiscount = (base: number, customer: Customer): number =>
77	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
78	
79	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
80	  isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
81	
82	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
83	  const base = itemsBasePremium(items);
84	  const modifierSurcharge = itemsModifierSurcharge(items);
85	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
86	  const discount = loyaltyDiscount(base, customer) + followUpDiscount(base, isFollowUp);
87	  return Math.ceil(base + modifierSurcharge + firstInsuranceSurcharge - discount + PROCESSING_FEE);
88	};
89	
90	const insuranceSum = (items: Item[]): number =>
91	  items.reduce((total, item) => total + unitInsuranceValue(item.type), 0);
92	
93	type Policy = { items: Item[]; capRemaining: number };
94	
95	const createPolicy = (items: Item[]): Policy => ({
96	  items,
97	  capRemaining: 2 * insuranceSum(items),
98	});
99	
100	const damagePayout = (damage: DamageEntry): number =>
101	  Math.max(0, damage.amount - DEDUCTIBLE);
102	
103	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
104	  const rawPayout = incident.damages.reduce(
105	    (total, damage) => total + damagePayout(damage),
106	    0,
107	  );
108	  const payout = Math.min(rawPayout, policy.capRemaining);
109	  policy.capRemaining -= payout;
110	  return { payout: Math.floor(payout), remainingCap: policy.capRemaining };
111	};
112	
113	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
114	  const policies = new Map<number, Policy>();
115	  let quoteCount = 0;
116	  const results: StepResult[] = scenario.steps.map((step, index) => {
117	    if (step.op === "quote") {
118	      const isFollowUp = quoteCount > 0;
119	      quoteCount += 1;
120	      policies.set(index, createPolicy(step.items));
121	      return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
122	    }
123	    const policy = policies.get(step.policy);
124	    if (!policy) throw new Error(`No policy at index ${step.policy}`);
125	    return processClaim(policy, step.incident);
126	  });
127	  return { results };
128	};
